import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";

const SideDrawer = () => {
  const [open, setOpen] = useState(false);
  const [profileImage, setProfileImage] = useState("");
  const navigate = useNavigate();

  const userId = localStorage.getItem("userId"); // 🔥 important

  // Load user-specific profile image
  useEffect(() => {
    const data = JSON.parse(localStorage.getItem(`profile_${userId}`)) || {};
    if (data.image) {
      setProfileImage(data.image);
    }
  }, [userId]);

  return (
    <>
      {/* ☰ Menu Button */}
      <button
        onClick={() => setOpen(!open)}
        style={{
          position: "fixed",
          top: "20px",
          left: "20px",
          zIndex: 9999,
          background: "#333",
          color: "#fff",
          padding: "10px",
          border: "none",
          cursor: "pointer",
          borderRadius: "5px",
        }}
      >
        ☰
      </button>

      {/* 👤 Profile Button / Image */}
      <div
        onClick={() => navigate("/dashboard/profile")} // ✅ FIXED ROUTE
        style={{
          position: "fixed",
          top: "20px",
          right: "20px",
          zIndex: 9999,
          cursor: "pointer",
          transition: "0.3s",
        }}
        onMouseOver={(e) => (e.currentTarget.style.transform = "scale(1.1)")}
        onMouseOut={(e) => (e.currentTarget.style.transform = "scale(1)")}
      >
        {profileImage ? (
          <img
            src={profileImage}
            alt="profile"
            style={{
              width: "45px",
              height: "45px",
              borderRadius: "50%",
              objectFit: "cover",
              border: "2px solid #ff6b6b",
            }}
          />
        ) : (
          <button
            style={{
              padding: "10px 20px",
              borderRadius: "25px",
              border: "none",
              background: "linear-gradient(45deg, #ff6b6b, #ff9f43)",
              color: "#fff",
              fontWeight: "bold",
              cursor: "pointer",
            }}
          >
            Profile
          </button>
        )}
      </div>

      {/* 📌 Sidebar */}
      <div
        style={{
          position: "fixed",
          top: 0,
          left: open ? "0" : "-250px",
          width: "250px",
          height: "100%",
          background: "#222",
          color: "#fff",
          transition: "0.3s",
          paddingTop: "60px",
          zIndex: 9998,
        }}
      >
        <ul style={{ listStyle: "none", padding: "0", margin: 0 }}>
          <li style={itemStyle} onClick={() => navigate("/")}>
            Home
          </li>
          <li style={itemStyle} onClick={() => navigate("/dashboard")}>
            Dashboard
          </li>
          <li style={itemStyle} onClick={() => navigate("/dashboard/profile")}>
            Profile
          </li>
        </ul>
      </div>
    </>
  );
};

const itemStyle = {
  padding: "15px",
  cursor: "pointer",
  borderBottom: "1px solid #444",
};

export default SideDrawer;
